// ============================================================================
// sync-worker-policy — regenerate the worker-consumable policy mirror.
// ----------------------------------------------------------------------------
// Single source of truth: packages/evidence-mapping/src/index.ts
// (@getkinetik/evidence-mapping). Cloudflare Pages Functions can't import the
// TypeScript package directly and the repo has no deploy-time build step, so
// we commit a generated ESM mirror under functions/api/_lib/ (matching the
// zero-dependency _lib/*.js convention used by bureauSign.js). The
// verify-device worker imports DEFAULT_POLICY + attestationToTier from there.
//
// This script reads the package's compiled dist/index.js (run the package
// build first — see the npm `policy:sync` script) and writes the mirror with
// a GENERATED banner and the source-map trailer stripped.
//
// Run:  npm run policy:sync
// CI rebuilds + reruns this and fails if the committed mirror is stale.
// ============================================================================

import { readFileSync, writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, resolve } from "node:path";

const here = dirname(fileURLToPath(import.meta.url));
const repoRoot = resolve(here, "..");

const DIST = resolve(
  repoRoot,
  "packages/evidence-mapping/dist/index.js",
);
const OUT = resolve(
  repoRoot,
  "functions/api/_lib/evidence-mapping.js",
);

const BANNER = `/**
 * GENERATED FILE
 *
 * Source:
 *   packages/evidence-mapping/src/index.ts
 *
 * Generated by:
 *   npm run policy:sync
 *
 * DO NOT EDIT
 */
`;

let compiled;
try {
  compiled = readFileSync(DIST, "utf8");
} catch {
  console.error(
    `[sync-worker-policy] could not read ${DIST}\n` +
      `Run the package build first:  npm run policy:build`,
  );
  process.exit(1);
}

// Strip the trailing //# sourceMappingURL=... line — the .map is not shipped
// alongside the worker mirror.
const body = compiled
  .replace(/\r\n/g, "\n")
  .replace(/^\/\/# sourceMappingURL=.*$\n?/m, "")
  .trimEnd();

const out = `${BANNER}\n${body}\n`;

let existing = null;
try {
  existing = readFileSync(OUT, "utf8").replace(/\r\n/g, "\n");
} catch {
  existing = null;
}

if (existing === out) {
  console.log(`[sync-worker-policy] up to date: ${OUT}`);
  process.exit(0);
}

writeFileSync(OUT, out, "utf8");
console.log(`[sync-worker-policy] wrote ${OUT}`);
